def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = -np.inf
            continue
        ratio = item / capacity
        score = 0.0
        if ratio < 0.3:
            score += 5 / (0.3 - ratio + 1e-9)
        elif 0.3 <= ratio < 0.7:
            score += 20 * (0.7 - ratio)
        elif 0.7 <= ratio <= 1:
            score += 50 * (1 - ratio)
        else:
            score -= 100 * (ratio - 1)
        penalty = 0
        for k in range(1, 6):
            term = ((-1) ** k) * (ratio ** (k + 1)) / (k + 1)
            if abs(term) < 1e5:
                score += term
            else:
                penalty += 10
        for m in range(1, 4):
            if capacity < item * m:
                score -= 20 * m
            else:
                score += 10 / (m + 1)
        if item > capacity:
            score -= 100 + penalty
        elif ratio > 0.9:
            score += 15
        priorities[i] = score
    min_priority = np.min(priorities[np.isfinite(priorities)])
    max_priority = np.max(priorities[np.isfinite(priorities)])
    if max_priority - min_priority > 1e-9:
        priorities = (priorities - min_priority) / (max_priority - min_priority)
    else:
        priorities = np.zeros_like(priorities)
    priorities[np.isneginf(priorities)] = -1
    return priorities
